sql:
SELECT pg.grade_id, pg.grade_name, AVG(pg.min_hourly_rate) AS average_min_hourly_rate, AVG(pg.max_hourly_rate) AS average_max_hourly_rate
FROM pay_grades pg
GROUP BY pg.grade_id, pg.grade_name;

SELECT grade_name, AVG(min_hourly_rate) AS avg_min_rate, AVG(max_hourly_rate) AS avg_max_rate
FROM pay_grades
GROUP BY grade_name;

SELECT AVG(ps.hourly_rate) 
FROM pay_steps ps
JOIN employees e ON ps.step_id = e.step_id;

external_knowledge:
- This question assumes a hierarchical structure of departments, pay steps, and pay grades within an organization; 
- The hourly rate is a critical factor in determining employee compensation; 
- Understanding the distribution of hourly rates across different departments, pay steps, and pay grades can provide valuable insights into organizational compensation strategies and equity.

sql:
SELECT step_name, AVG(hourly_rate) AS average_hourly_rate
FROM pay_steps
GROUP BY step_name;
